mapper.select:
SELECT
  ws.max_wind_speed
FROM
  v_uasl_design_max_wind_speed ws


    JOIN t_remote_data rd ON ws.aircraft_info_id = rd.aircraft_info_id
    WHERE rd.uasl_reservation_id = #{uaslReservationId,jdbcType=VARCHAR}


    WHERE ws.maker = #{maker,jdbcType=VARCHAR}
      AND ws.model_number = #{modelNumber,jdbcType=VARCHAR}
